class Solution {
public:
    vector<vector<string>> findDuplicate(vector<string>& paths) {
        unordered_map<string, vector<string>> contentToPaths;
        for (const string& path : paths) {
            size_t start = 0;
            while (start < path.size()) {
                size_t end = path.find(' ', start);
                if (end == string::npos) end = path.size();
                string dir = path.substr(0, end);
                size_t space = path.find(' ', end);
                if (space == string::npos) space = path.size();
                string file = path.substr(end + 1, space - end - 1);
                size_t open = file.find('(');
                string content = file.substr(open + 1, file.size() - open - 2);
                contentToPaths[content].push_back(dir + "/" + file.substr(0, open));
                start = space + 1;
            }
        }
        vector<vector<string>> result;
        for (auto& pair : contentToPaths) {
            if (pair.second.size() > 1) {
                result.push_back(pair.second);
            }
        }
        return result;
    }
};
